static float DistanceToSeg(float px, float py, float ax, float ay, float bx, float by)
{
    var sx = bx - ax;
    var sy = by - ay;
    var lenSq = sx * sx + sy * sy;
    if (lenSq < 0.000001f)
    {
        var dx = px - ax;
        var dy = py - ay;
        return MathF.Sqrt(dx * dx + dy * dy);
    }
    var t = Math.Clamp(((px - ax) * sx + (py - ay) * sy) / lenSq, 0f, 1f);
    var nx = ax + sx * t;
    var ny = ay + sy * t;
    var dx2 = px - nx;
    var dy2 = py - ny;
    return MathF.Sqrt(dx2 * dx2 + dy2 * dy2);
}

static float SegMask(float px, float py, float ax, float ay, float bx, float by, float w)
{
    var d = DistanceToSeg(px, py, ax, ay, bx, by);
    return 1f - SmoothStep(w, w + 0.02f, d);
}

static float FractureMask(float lx, float ly, int bw, int bh, int bx, int by, int sd, float dens, float wScale)
{
    var crackPresence = 0.08f + dens * 0.82f;
    if (HashToUnit(bx, by, sd + 205) > crackPresence) return 0f;

    var aspect = bw / (float)Math.Max(1, bh);
    var routeSelector = HashToUnit(bx, by, sd + 211);
    var startOff = 0.18f + HashToUnit(bx, by, sd + 223) * 0.2f;
    var endOff = 0.62f + HashToUnit(bx, by, sd + 227) * 0.2f;

    float saX, saY, eaX, eaY;

    if (aspect > 1.25f)
    {
        if (routeSelector < 0.62f) { saX = 0.22f + startOff * 0.45f; saY = 0f; eaX = 0.54f + endOff * 0.25f; eaY = 1f; }
        else { saX = 0f; saY = startOff; eaX = 1f; eaY = 0.58f + endOff * 0.18f; }
    }
    else if (aspect < 0.8f)
    {
        if (routeSelector < 0.62f) { saX = 0f; saY = 0.22f + startOff * 0.45f; eaX = 1f; eaY = 0.54f + endOff * 0.25f; }
        else { saX = startOff; saY = 0f; eaX = 0.58f + endOff * 0.18f; eaY = 1f; }
    }
    else if (routeSelector < 0.28f) { saX = 0f; saY = startOff; eaX = 1f; eaY = 0.58f + endOff * 0.18f; }
    else if (routeSelector < 0.56f) { saX = 0.22f + startOff * 0.45f; saY = 0f; eaX = 0.54f + endOff * 0.25f; eaY = 1f; }
    else if (routeSelector < 0.78f) { saX = 0f; saY = 0.62f + startOff * 0.18f; eaX = 1f; eaY = 0.18f + endOff * 0.2f; }
    else { saX = 0.62f + startOff * 0.18f; saY = 0f; eaX = 0.18f + endOff * 0.2f; eaY = 1f; }

    var dX = eaX - saX;
    var dY = eaY - saY;
    var dirLen = MathF.Sqrt(dX * dX + dY * dY);
    if (dirLen < 0.0001f) return 0f;
    dX /= dirLen; dY /= dirLen;
    var nX = -dY; var nY = dX;

    var bendStr = 0.08f + dens * 0.12f;
    var b1t = 0.24f + HashToUnit(bx, by, sd + 229) * 0.18f;
    var b2t = 0.6f + HashToUnit(bx, by, sd + 233) * 0.16f;
    var b1o = (HashToUnit(bx, by, sd + 239) - 0.5f) * bendStr;
    var b2o = (HashToUnit(bx, by, sd + 241) - 0.5f) * bendStr * 1.2f;
    if (MathF.Abs(b1o - b2o) < 0.03f) b2o = -b2o * 0.85f;

    var b1x = Math.Clamp(Lerp(saX, eaX, b1t) + nX * b1o, 0.04f, 0.96f);
    var b1y = Math.Clamp(Lerp(saY, eaY, b1t) + nY * b1o, 0.04f, 0.96f);
    var b2x = Math.Clamp(Lerp(saX, eaX, b2t) + nX * b2o, 0.04f, 0.96f);
    var b2y = Math.Clamp(Lerp(saY, eaY, b2t) + nY * b2o, 0.04f, 0.96f);

    var w = (0.018f + dens * 0.022f) * wScale;
    var s1 = SegMask(lx, ly, saX, saY, b1x, b1y, w);
    var s2 = SegMask(lx, ly, b1x, b1y, b2x, b2y, w * 0.92f);
    var s3 = SegMask(lx, ly, b2x, b2y, eaX, eaY, w * 0.86f);
    var primary = Math.Max(s1, Math.Max(s2, s3));

    var branchChance = dens * 0.52f;
    if (HashToUnit(bx, by, sd + 257) > branchChance) return primary;

    var branchIsB1 = HashToUnit(bx, by, sd + 263) > 0.5f;
    var brAX = branchIsB1 ? b1x : b2x;
    var brAY = branchIsB1 ? b1y : b2y;
    var brFwd = 0.04f + dens * 0.08f + HashToUnit(bx, by, sd + 269) * 0.04f;
    var brSide = (0.08f + dens * 0.12f) * (HashToUnit(bx, by, sd + 271) > 0.5f ? 1f : -1f);
    var brEndX = Math.Clamp(brAX + dX * brFwd + nX * brSide, 0.04f, 0.96f);
    var brEndY = Math.Clamp(brAY + dY * brFwd + nY * brSide, 0.04f, 0.96f);
    var branch = SegMask(lx, ly, brAX, brAY, brEndX, brEndY, w * 0.82f);

    return Math.Max(primary, branch * 0.9f);
}

var size = context.TileSize;
var seed = GetInt(parameters, "seed", 42);
var hTileCount = Math.Max(1, GetInt(parameters, "horizontalTileCount", 3));
var vTileCount = Math.Max(1, GetInt(parameters, "verticalTileCount", 3));
var crackDensity = GetFloat(parameters, "crackDensity", 0.3f);
var mossDensity = GetFloat(parameters, "mossDensity", 0.3f);

// Stone palette (0..1 floats)
var borderR = 52f / 255f; var borderG = 52f / 255f; var borderB = 56f / 255f;
var shadowR = 82f / 255f; var shadowG = 82f / 255f; var shadowB = 88f / 255f;
var midR = 118f / 255f; var midG = 118f / 255f; var midB = 124f / 255f;
var lightR = 148f / 255f; var lightG = 148f / 255f; var lightB = 154f / 255f;
var hlR = 168f / 255f; var hlG = 168f / 255f; var hlB = 174f / 255f;
var mossDR = 54f / 255f; var mossDG = 78f / 255f; var mossDB = 48f / 255f;
var mossMR = 72f / 255f; var mossMG = 104f / 255f; var mossMB = 64f / 255f;
var mossLR = 96f / 255f; var mossLG = 132f / 255f; var mossLB = 80f / 255f;

var result = new PixelBuffer(size, size);
result.ParallelForEachPixel((x, y) =>
{
    var wx = Mod(x, size);
    var wy = Mod(y, size);

    var by = wy * vTileCount / size;
    var rowStart = by * size / vTileCount;
    var rowEnd = (by + 1) * size / vTileCount;
    var blockH = Math.Max(1, rowEnd - rowStart);
    var ly = wy - rowStart;

    var avgBlockW = Math.Max(1, size / hTileCount);
    var rowOff = (by % 2 == 1) ? Math.Max(1, avgBlockW / 2) : 0;
    var adjX = Mod(wx + rowOff, size);
    var bx = adjX * hTileCount / size;
    var colStart = bx * size / hTileCount;
    var colEnd = (bx + 1) * size / hTileCount;
    var blockW = Math.Max(1, colEnd - colStart);
    var lx = adjX - colStart;

    float r, g, b;

    if (lx == 0 || ly == 0)
    {
        r = borderR; g = borderG; b = borderB;
    }
    else
    {
        var innerW = Math.Max(1, blockW - 1);
        var innerH = Math.Max(1, blockH - 1);
        var locX = Math.Clamp((lx - 0.5f) / innerW, 0f, 1f);
        var locY = Math.Clamp((ly - 0.5f) / innerH, 0f, 1f);
        var blockHash = HashToUnit(bx, by, seed + 10);

        var cDx = locX - 0.5f;
        var cDy = locY - 0.5f;
        var centerDist = MathF.Sqrt(cDx * cDx + cDy * cDy);
        var centerLift = 1f - SmoothStep(0.12f, 0.72f, centerDist);
        var lightBias = (1f - locX) * 0.38f + (1f - locY) * 0.62f;
        var surfNoise = TileableFractalNoise(wx * (0.45f + blockHash * 0.2f), wy * (0.45f + (1f - blockHash) * 0.2f), size, 3, 0.55f, 2f, seed + 70 + bx * 17 + by * 31);

        var tone = 0.18f + blockHash * 0.22f + centerLift * 0.26f + lightBias * 0.24f + (surfNoise - 0.5f) * 0.24f;

        if (tone > 0.82f) { r = hlR; g = hlG; b = hlB; }
        else if (tone > 0.63f) { r = lightR; g = lightG; b = lightB; }
        else if (tone > 0.36f) { r = midR; g = midG; b = midB; }
        else { r = shadowR; g = shadowG; b = shadowB; }

        if (lx == 1 || ly == 1)
        {
            r = (r + lightR) * 0.5f; g = (g + lightG) * 0.5f; b = (b + lightB) * 0.5f;
        }

        if (lx >= blockW - 1 || ly >= blockH - 1)
        {
            r = (r + shadowR) * 0.5f; g = (g + shadowG) * 0.5f; b = (b + shadowB) * 0.5f;
        }

        // Cracks
        if (crackDensity > 0f)
        {
            var fBand = FractureMask(locX, locY, blockW, blockH, bx, by, seed, crackDensity, 2.1f);
            var fCore = FractureMask(locX, locY, blockW, blockH, bx, by, seed, crackDensity, 1f);

            if (fBand > 0f)
            {
                r = Lerp(r, shadowR, fBand * 0.45f);
                g = Lerp(g, shadowG, fBand * 0.45f);
                b = Lerp(b, shadowB, fBand * 0.45f);
            }

            if (fCore > 0f)
            {
                r = Lerp(r, borderR, fCore);
                g = Lerp(g, borderG, fCore);
                b = Lerp(b, borderB, fCore);
            }
        }

        // Moss
        if (mossDensity > 0f)
        {
            var edgeDist = MathF.Min(MathF.Min(locX, 1f - locX), MathF.Min(locY, 1f - locY));
            var edgePocket = 1f - SmoothStep(0.08f, 0.3f, edgeDist);
            var shadowPocket = SmoothStep(0.48f, 0.92f, locY * 0.7f + locX * 0.3f);
            var moisture = TileableFractalNoise(wx * 0.75f, wy * 0.75f, size, 3, 0.58f, 2f, seed + 301);
            var patchN = TileableFractalNoise(wx * 1.35f, wy * 1.35f, size, 2, 0.5f, 2f, seed + 337);
            var mossN = moisture * 0.68f + patchN * 0.32f;
            var mossAff = Math.Clamp(crackDensity * 0.8f + edgePocket * 0.7f + shadowPocket * 0.35f, 0f, 1f);
            var thresh = 0.9f - mossDensity * 0.34f - mossAff * 0.24f;

            if (mossAff > 0.16f && mossN > thresh)
            {
                var mossTone = mossN + crackDensity * 0.25f;
                float msR, msG, msB;
                if (mossTone > 0.78f) { msR = mossLR; msG = mossLG; msB = mossLB; }
                else if (mossTone > 0.52f) { msR = mossMR; msG = mossMG; msB = mossMB; }
                else { msR = mossDR; msG = mossDG; msB = mossDB; }
                var blend = Math.Clamp(0.42f + mossAff * 0.35f, 0f, 0.88f);
                r = Lerp(r, msR, blend);
                g = Lerp(g, msG, blend);
                b = Lerp(b, msB, blend);
            }
        }
    }

    result.SetPixel(x, y, Math.Clamp(r, 0f, 1f), Math.Clamp(g, 0f, 1f), Math.Clamp(b, 0f, 1f), 1f);
});

return result;
